"use client";

/* ════════════════════════════════════════════════════════════════════════
   BridgeReturn — write surface for resolving a customer return.
   Ported from /Users/mac/Downloads/MAGELLAN UX/Bridge/Opertation/
   magellan-bridge-return.html

   Pattern:
   - Return summary (to-restock, written-off, refund total)
   - "What comes back" — per-item disposition segmented (Restock / Write off)
   - "Refund" — amount + method + restocking note
   - Verdict (REFUND / PARTIAL / DENY) with 4 factor dots
   - "What this resolves" — This return + Pattern & signal tiers
   ════════════════════════════════════════════════════════════════════════ */

import { useMemo, useState } from "react";
import { useBridge } from "@/features/bridge/hooks/use-bridge";

type Disposition = "restock" | "lost";

interface ItemRaw {
  name: string;
  qty: number;
  landed: number;
  price: number;
  disp: Disposition;
}

const RETURN_ID = "RT-2208";
const ORDER_ID = "#18472";
const REASON = "arrived wilted";
const CUSTOMER = "VIP, 11 prior orders";

const ITEMS_INIT: ItemRaw[] = [
  { name: "Pastel Tulip Bouquet", qty: 1, landed: 362, price: 1290, disp: "lost" },
  { name: "Ceramic Vase — Tall White", qty: 1, landed: 24, price: 290, disp: "restock" },
];

const FULL_REFUND = ITEMS_INIT.reduce((a, i) => a + i.price * i.qty, 0);

const fmtUSD = (v: number) => `$${Math.round(v).toLocaleString()}`;
const fmtUSDShort = (v: number) =>
  v >= 1000 ? `$${(v / 1000).toFixed(v >= 10000 ? 0 : 1)}K` : `$${Math.round(v)}`;

export function BridgeReturn() {
  const { setPage } = useBridge();

  const [items, setItems] = useState<ItemRaw[]>(ITEMS_INIT);
  const [refundInput, setRefundInput] = useState(`$${FULL_REFUND.toLocaleString()}`);
  const [note, setNote] = useState("");
  const [confirmed, setConfirmed] = useState(false);

  const setDisp = (i: number, d: Disposition) => {
    setItems((cur) => cur.map((it, idx) => (idx === i ? { ...it, disp: d } : it)));
  };

  // Derived
  const restocked = items.filter((i) => i.disp === "restock");
  const lost = items.filter((i) => i.disp === "lost");
  const restockUnits = restocked.reduce((a, i) => a + i.qty, 0);
  const lostUnits = lost.reduce((a, i) => a + i.qty, 0);
  const recovered = restocked.reduce((a, i) => a + i.landed * i.qty, 0);
  const writeOff = lost.reduce((a, i) => a + i.landed * i.qty, 0);

  const refund = useMemo(() => {
    const n = parseFloat(refundInput.replace(/[^0-9.]/g, ""));
    return isNaN(n) ? 0 : n;
  }, [refundInput]);
  const isPartial = refund < FULL_REFUND;

  // Net cost = what we lost as inventory write-off (refund is revenue reversal)
  const netCost = writeOff;

  // Verdict
  const verdict: "refund" | "partial" | "deny" =
    refund === 0 ? "deny" : isPartial ? "partial" : "refund";
  const verdictMark =
    verdict === "refund" ? "REFUND" : verdict === "partial" ? "PARTIAL" : "DENY";
  const verdictLine =
    verdict === "refund"
      ? "Genuine quality issue — refund in full. Resellable units go back to stock; damaged ones are a write-off."
      : verdict === "partial"
        ? "Partial refund — what's resellable returns to stock at landed cost, the rest is the write-off you're crediting."
        : "No refund issued. Customer relationship cost is the real expense here — flag if this happens again.";

  const resolve = () => {
    setConfirmed(true);
    setTimeout(() => {
      setConfirmed(false);
      setPage("home");
    }, 1800);
  };

  return (
    <div className="bridge-content">
      <div className="bridge-page-head">
        <div className="bridge-page-head-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
            <path d="M9 14 L4 14 L4 9" />
            <path d="M4 14 a8 8 0 1 0 2 -6" />
          </svg>
        </div>
        <div>
          <div className="bridge-page-head-title">Process Return</div>
          <div className="bridge-page-head-sub">
            Decide what comes back to stock and what&rsquo;s lost, confirm the refund, and see the true cost of the return.
          </div>
        </div>
      </div>

      {/* Return summary */}
      <div className="bridge-rb-sku">
        <div className="bridge-rb-sku-main">
          <div className="bridge-rb-sku-name">
            Return #{RETURN_ID} — Order {ORDER_ID}
          </div>
          <div className="bridge-rb-sku-meta">
            Requested by customer 2 days ago · reason: &ldquo;{REASON}&rdquo; · {items.length} items
          </div>
        </div>
        <div className="bridge-rb-sku-stats">
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{restockUnits}</span>
            <span className="bridge-rb-stat-k">to restock</span>
          </div>
          <div className="bridge-rb-stat">
            <span className={`bridge-rb-stat-v${lostUnits > 0 ? " alert" : ""}`}>
              {lostUnits}
            </span>
            <span className="bridge-rb-stat-k">written off</span>
          </div>
          <div className="bridge-rb-stat">
            <span className="bridge-rb-stat-v">{fmtUSD(refund)}</span>
            <span className="bridge-rb-stat-k">refund</span>
          </div>
        </div>
      </div>

      {/* Disposition */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">What comes back</span>
          <span className="bridge-ni-source manual">
            ✏ Magellan suggests by reason &amp; condition — adjust
          </span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-cost bridge-ni-span" style={{ marginTop: 0 }}>
            <div className="bridge-ni-cost-head">
              <span className="bridge-ni-label">Items returned</span>
              <span className="bridge-ni-cost-note">set the disposition of each</span>
            </div>
            <div className="bridge-rt-disp">
              {items.map((it, i) => (
                <div key={it.name} className="bridge-rt-line">
                  <span className="rt-name">{it.name}</span>
                  <span className="rt-qty">qty {it.qty}</span>
                  <div className="bridge-rt-seg">
                    <button
                      className={it.disp === "restock" ? "on" : ""}
                      data-d="restock"
                      onClick={() => setDisp(i, "restock")}
                      type="button"
                    >
                      Restock
                    </button>
                    <button
                      className={it.disp === "lost" ? "on" : ""}
                      data-d="lost"
                      onClick={() => setDisp(i, "lost")}
                      type="button"
                    >
                      Write off
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Refund */}
      <div className="bridge-ni-card">
        <div className="bridge-ni-card-head">
          <span className="bridge-ni-section">Refund</span>
          <span className="bridge-ni-source manual">✏ Adjust if partial</span>
        </div>
        <div className="bridge-ni-grid">
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Refund amount</span>
            <input
              className="bridge-ni-input"
              type="text"
              value={refundInput}
              onChange={(e) => setRefundInput(e.target.value)}
            />
          </div>
          <div className="bridge-ni-field">
            <span className="bridge-ni-label">Method</span>
            <div className="bridge-ni-readout">Original payment · Omise</div>
          </div>
          <div className="bridge-ni-field bridge-ni-span">
            <span className="bridge-ni-label">
              Restocking note
              <span className="bridge-ni-hint">optional — visible to the customer</span>
            </span>
            <input
              className="bridge-ni-input"
              type="text"
              placeholder="e.g. full refund, no restocking fee"
              value={note}
              onChange={(e) => setNote(e.target.value)}
            />
          </div>
        </div>
      </div>

      {/* Verdict */}
      <div className={`bridge-rb-verdict${verdict === "refund" ? "" : verdict === "partial" ? " hold" : " wait"}`}>
        <div
          className="bridge-rb-verdict-mark"
          style={
            verdict === "refund"
              ? { color: "var(--d-finance)", width: 100 }
              : { width: 100 }
          }
        >
          {verdictMark}
        </div>
        <div className="bridge-rb-verdict-body">
          <div className="bridge-rb-verdict-line">{verdictLine}</div>
          <div className="bridge-rb-verdict-factors">
            <div className="bridge-rb-factor">
              <span className="bridge-rb-factor-dot ok" />
              <span className="bridge-rb-factor-k">Reason</span>
              <span className="bridge-rb-factor-v">
                Quality (wilted) — our fault, full refund fair
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${restockUnits > 0 ? "ok" : "bad"}`} />
              <span className="bridge-rb-factor-k">Recoverable</span>
              <span className="bridge-rb-factor-v">
                {restockUnits} of {items.length} resellable — {fmtUSD(recovered)} back to stock
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className={`bridge-rb-factor-dot ${writeOff > 0 ? "warn" : "ok"}`} />
              <span className="bridge-rb-factor-k">Cost of return</span>
              <span className="bridge-rb-factor-v">
                {writeOff > 0 ? `${fmtUSD(writeOff)} written off + refund` : "no write-off"}
              </span>
            </div>
            <div className="bridge-rb-factor">
              <span className="bridge-rb-factor-dot ok" />
              <span className="bridge-rb-factor-k">Customer</span>
              <span className="bridge-rb-factor-v">{CUSTOMER} — worth keeping</span>
            </div>
          </div>
        </div>
      </div>

      {/* What this resolves */}
      <div className="bridge-ni-outcome">
        <div className="bridge-ni-outcome-head">
          <span className="m-mark">M</span> What this resolves
          <span className="bridge-ni-outcome-prov firm">Computed from the return</span>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">This return</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">Back to sellable stock</span>
              <span className="v good">+{restockUnits} unit{restockUnits === 1 ? "" : "s"}</span>
              <span className="kk">{fmtUSD(recovered)} recovered</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Written off</span>
              <span className={`v${lostUnits > 0 ? " alert" : ""}`}>
                {lostUnits} unit{lostUnits === 1 ? "" : "s"}
              </span>
              <span className="kk">{fmtUSD(writeOff)} cost lost</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Refund issued</span>
              <span className="v">{fmtUSD(refund)}</span>
              <span className="kk">to original payment</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Net cost of return</span>
              <span className="v">{fmtUSD(netCost)}</span>
              <span className="kk">write-off; refund nets to revenue reversal</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-tier">
          <div className="bridge-ni-tier-label">Pattern &amp; signal</div>
          <div className="bridge-ni-outcome-grid">
            <div className="bridge-ni-out">
              <span className="k">This SKU&rsquo;s return rate</span>
              <span className="v alert">4.2%</span>
              <span className="kk">above 2.5% category avg</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Reason trend</span>
              <span className="v">&ldquo;wilted&rdquo; ×3 this month</span>
              <span className="kk">flag to ops</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Likely cause</span>
              <span className="v">cold-chain or age</span>
              <span className="kk">worth investigating</span>
            </div>
            <div className="bridge-ni-out">
              <span className="k">Customer retained?</span>
              <span className="v good">likely</span>
              <span className="kk">fast full refund</span>
            </div>
          </div>
        </div>

        <div className="bridge-ni-outcome-note">
          Processing a return splits it by <b>disposition</b> — resellable units go back to stock at landed cost, damaged units are written off, and the refund posts as a revenue reversal. Magellan also watches the <b>pattern</b>: a SKU returning above its category rate for the same reason is a quality signal, not just a refund — surfaced so the cause gets fixed, not just the symptom.
        </div>
      </div>

      {/* Commit */}
      <div className="bridge-ni-commit">
        <div className="bridge-ni-commit-note">
          This drafts the resolution — the refund <b>isn&rsquo;t issued</b> and stock isn&rsquo;t updated until you confirm. Reversible.
        </div>
        <div className="bridge-ni-commit-btns">
          <button className="bridge-ni-cancel" type="button" onClick={() => setPage("home")}>
            Hold
          </button>
          <button
            className={`bridge-ni-create${confirmed ? " done" : ""}`}
            type="button"
            onClick={resolve}
            disabled={confirmed}
          >
            {confirmed
              ? "Resolution drafted ✓"
              : `Refund ${fmtUSDShort(refund)} & resolve →`}
          </button>
        </div>
      </div>
    </div>
  );
}
